import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import * as BaseToggleGroup from '../../base-ui/toggle-group'
import * as Toggle from '../toggle'

// MODEL

export type ToggleGroupChangeReason = BaseToggleGroup.ToggleGroupChangeReason
export type ToggleGroupHighlightChange =
  BaseToggleGroup.ToggleGroupHighlightChange
export type ToggleGroupItemDescriptor =
  BaseToggleGroup.ToggleGroupItemDescriptor
export type ToggleGroupOrientation = BaseToggleGroup.ToggleGroupOrientation
export type ToggleGroupSelectionMode = BaseToggleGroup.ToggleGroupSelectionMode
export type ToggleGroupValueChange = BaseToggleGroup.ToggleGroupValueChange

export const ToggleGroupSpacing = S.Union([
  S.Literal(0),
  S.Literal(1),
  S.Literal(2),
  S.Literal(4),
])
export type ToggleGroupSpacing = typeof ToggleGroupSpacing.Type

export const toggleGroupSpacingValues: ReadonlyArray<ToggleGroupSpacing> = [
  0, 1, 2, 4,
]

export const ToggleGroupStyleOptions = S.Struct({
  className: S.optional(S.String),
  itemClassName: S.optional(S.String),
  variant: S.optional(Toggle.ToggleVariant),
  size: S.optional(Toggle.ToggleSize),
  spacing: S.optional(ToggleGroupSpacing),
})
export type ToggleGroupStyleOptions = typeof ToggleGroupStyleOptions.Type

// UPDATE

export const {
  highlightChange,
  isPressed,
  itemFocusSelector,
  nextValue,
  pressedState,
  valueChange,
} = BaseToggleGroup

// VIEW

export type ToggleGroupAttributes<Message> =
  BaseToggleGroup.ToggleGroupAttributes<Message>
export type ToggleGroupItemAttributes<Message> =
  BaseToggleGroup.ToggleGroupItemAttributes<Message>

export type ViewConfig<Message> = Omit<
  BaseToggleGroup.ViewConfig<Message>,
  'toView'
> &
  ToggleGroupStyleOptions &
  Readonly<{
    dir?: string
    toView?: (attributes: ToggleGroupAttributes<Message>) => Html
  }>

export const toggleGroupBaseClassName =
  'group/toggle-group flex w-fit flex-row items-center gap-[--spacing(var(--gap))] rounded-lg data-[size=sm]:rounded-[min(var(--radius-md),10px)] data-vertical:flex-col data-vertical:items-stretch'

export const toggleGroupItemBaseClassName =
  'shrink-0 group-data-[spacing=0]/toggle-group:rounded-none group-data-[spacing=0]/toggle-group:px-2 focus:z-10 focus-visible:z-10 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-end]:pr-1.5 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-start]:pl-1.5 group-data-horizontal/toggle-group:data-[spacing=0]:first:rounded-l-lg group-data-vertical/toggle-group:data-[spacing=0]:first:rounded-t-lg group-data-horizontal/toggle-group:data-[spacing=0]:last:rounded-r-lg group-data-vertical/toggle-group:data-[spacing=0]:last:rounded-b-lg group-data-horizontal/toggle-group:data-[spacing=0]:data-[variant=outline]:border-l-0 group-data-vertical/toggle-group:data-[spacing=0]:data-[variant=outline]:border-t-0 group-data-horizontal/toggle-group:data-[spacing=0]:data-[variant=outline]:first:border-l group-data-vertical/toggle-group:data-[spacing=0]:data-[variant=outline]:first:border-t'

export const toggleGroupClassName = ({
  className,
}: Pick<ToggleGroupStyleOptions, 'className'> = {}): string =>
  cn(toggleGroupBaseClassName, className)

export const toggleGroupItemClassName = ({
  className,
  dir,
  size = 'default',
  variant = 'default',
}: Pick<ToggleGroupStyleOptions, 'className' | 'size' | 'variant'> &
  Readonly<{ dir?: string | undefined }> = {}): string =>
  cn(
    toggleGroupItemBaseClassName,
    Toggle.toggleVariants({ dir, size, variant }),
    className,
  )

const optionalDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: string | number | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === undefined ? [] : [h.DataAttribute(name, String(value))]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    'className' | 'dir' | 'orientation' | 'size' | 'spacing' | 'variant'
  >,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'toggle-group'),
  ...optionalDataAttribute(h, 'variant', config.variant),
  ...optionalDataAttribute(h, 'size', config.size),
  h.DataAttribute('spacing', String(config.spacing ?? 2)),
  h.DataAttribute('orientation', config.orientation ?? 'horizontal'),
  h.Style({ '--gap': String(config.spacing ?? 2) }),
  h.Class(toggleGroupClassName({ className: config.className })),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    'dir' | 'itemClassName' | 'size' | 'spacing' | 'variant'
  >,
): ReadonlyArray<Attribute<Message>> => {
  const variant = config.variant ?? 'default'
  const size = config.size ?? 'default'

  return [
    h.DataAttribute('slot', 'toggle-group-item'),
    h.DataAttribute('variant', variant),
    h.DataAttribute('size', size),
    h.DataAttribute('spacing', String(config.spacing ?? 2)),
    h.Class(
      toggleGroupItemClassName({
        className: config.itemClassName,
        dir: config.dir,
        size,
        variant,
      }),
    ),
  ]
}

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: ToggleGroupAttributes<Message>,
): ToggleGroupAttributes<Message> => ({
  root: [...attributes.root, ...rootAttributes(h, config)],
  items: attributes.items.map(item => ({
    item: item.item,
    root: [...item.root, ...itemAttributes(h, config)],
  })),
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, ...baseConfig } = config

  return BaseToggleGroup.view<Message>({
    ...baseConfig,
    toView: attributes => {
      const toggleGroupAttributes = shadcnAttributes(h, config, attributes)

      if (toView !== undefined) {
        return toView(toggleGroupAttributes)
      }

      return h.div(
        [...toggleGroupAttributes.root],
        toggleGroupAttributes.items.map(item =>
          h.button([...item.root], [item.item.label ?? item.item.value]),
        ),
      )
    },
  })
}

import type { Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import type { ToggleSize, ToggleVariant } from '../toggle'
import { view as ToggleGroup } from './index'
import type {
  ToggleGroupSpacing as ToggleGroupSpacingValue,
  ToggleGroupValueChange,
} from './index'

type IconName = 'alignCenter' | 'alignLeft' | 'alignRight' | 'bold' | 'italic'

export type ToggleGroupExampleController<Message> = Readonly<{
  valueFor: (
    groupId: string,
    defaultValue: ReadonlyArray<string>,
  ) => ReadonlyArray<string>
  onValueChange: (groupId: string, change: ToggleGroupValueChange) => Message
}>

const toggleGroupValue = <Message>(
  controller: ToggleGroupExampleController<Message> | undefined,
  groupId: string,
  defaultValue: ReadonlyArray<string>,
): ReadonlyArray<string> =>
  controller?.valueFor(groupId, defaultValue) ?? defaultValue

const iconPaths: Readonly<Record<IconName, string>> = {
  alignCenter: 'M17 12H7m12-6H5m14 12H5',
  alignLeft: 'M21 6H3m15 6H3m11 6H3',
  alignRight: 'M21 6H3m18 6H6m15 6H10',
  bold: 'M6 12h9a4 4 0 0 0 0-8H7a1 1 0 0 0-1 1v14a1 1 0 0 0 1 1h9a4 4 0 0 0 0-8',
  italic: 'M19 4h-9m4 16H5m10-16-4 16',
}

const iconClassNames: Readonly<Record<IconName, string>> = {
  alignCenter: 'lucide lucide-align-center-icon',
  alignLeft: 'lucide lucide-align-left-icon',
  alignRight: 'lucide lucide-align-right-icon',
  bold: 'lucide lucide-bold-icon',
  italic: 'lucide lucide-italic-icon',
}

const icon = (name: IconName): Html => {
  const h = html<never>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      h.Class(iconClassNames[name]),
      h.AriaHidden(true),
    ],
    [h.path([h.D(iconPaths[name])], [])],
  )
}

const items = [
  { id: 'align-left', value: 'left', label: 'Left' },
  { id: 'align-center', value: 'center', label: 'Center' },
  { id: 'align-right', value: 'right', label: 'Right' },
]

const formattingItems = [
  { id: 'format-bold', value: 'bold', label: 'Bold' },
  { id: 'format-italic', value: 'italic', label: 'Italic' },
]

const group = <Message>(
  config: Readonly<{
    ariaLabel: string
    children: (h: ReturnType<typeof html<Message>>) => ReadonlyArray<Html>
    className?: string
    dir?: string
    itemClassName?: string
    orientation?: 'horizontal' | 'vertical'
    selectionMode?: 'single' | 'multiple'
    size?: ToggleSize
    spacing?: ToggleGroupSpacingValue
    value?: ReadonlyArray<string>
    variant?: ToggleVariant
  }>,
  controller: ToggleGroupExampleController<Message> | undefined,
): Html => {
  const h = html<Message>()

  return ToggleGroup<Message>({
    value: toggleGroupValue(
      controller,
      config.ariaLabel,
      config.value ?? ['center'],
    ),
    items,
    ...(config.className === undefined ? {} : { className: config.className }),
    ...(config.dir === undefined ? {} : { dir: config.dir }),
    ...(config.itemClassName === undefined
      ? {}
      : { itemClassName: config.itemClassName }),
    ...(config.orientation === undefined
      ? {}
      : { orientation: config.orientation }),
    ...(config.selectionMode === undefined
      ? {}
      : { selectionMode: config.selectionMode }),
    ...(config.size === undefined ? {} : { size: config.size }),
    ...(config.spacing === undefined ? {} : { spacing: config.spacing }),
    ...(config.variant === undefined ? {} : { variant: config.variant }),
    ...(controller === undefined
      ? {}
      : {
          onValueChange: change =>
            controller.onValueChange(config.ariaLabel, change),
        }),
    toView: attributes =>
      h.div(
        [...attributes.root, h.AriaLabel(config.ariaLabel)],
        config
          .children(h)
          .map((child, index) =>
            h.button([...(attributes.items[index]?.root ?? [])], [child]),
          ),
      ),
  })
}

const alignmentChildren = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Html> => [
  h.span([h.DataAttribute('icon', 'inline-start')], [icon('alignLeft')]),
  h.span([h.DataAttribute('icon', 'inline-start')], [icon('alignCenter')]),
  h.span([h.DataAttribute('icon', 'inline-start')], [icon('alignRight')]),
]

export const ToggleGroupDemo = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  group<Message>(
    {
      ariaLabel: 'Text alignment',
      variant: 'outline',
      children: alignmentChildren,
    },
    controller,
  )

export const ToggleGroupDisabled = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  ToggleGroup<Message>({
    value: toggleGroupValue(controller, 'Disabled formatting', ['bold']),
    selectionMode: 'multiple',
    variant: 'outline',
    items: [
      { id: 'format-bold', value: 'bold', label: 'Bold' },
      { id: 'format-italic', value: 'italic', label: 'Italic' },
      {
        id: 'format-strikethrough',
        value: 'strikethrough',
        label: 'Disabled',
        isDisabled: true,
      },
    ],
    ...(controller === undefined
      ? {}
      : {
          onValueChange: change =>
            controller.onValueChange('Disabled formatting', change),
        }),
  })

export const ToggleGroupFontWeightSelector = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html => {
  const h = html<Message>()

  return ToggleGroup<Message>({
    value: toggleGroupValue(controller, 'Font weight', ['bold']),
    selectionMode: 'multiple',
    variant: 'outline',
    items: formattingItems,
    ...(controller === undefined
      ? {}
      : {
          onValueChange: change =>
            controller.onValueChange('Font weight', change),
        }),
    toView: attributes =>
      h.div(
        [...attributes.root, h.AriaLabel('Font weight')],
        [
          h.button([...(attributes.items[0]?.root ?? [])], [icon('bold')]),
          h.button([...(attributes.items[1]?.root ?? [])], [icon('italic')]),
        ],
      ),
  })
}

export const ToggleGroupOutline = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  group<Message>(
    {
      ariaLabel: 'Text alignment outline',
      variant: 'outline',
      spacing: 0,
      children: alignmentChildren,
    },
    controller,
  )

export const ToggleGroupRtl = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  group<Message>(
    {
      ariaLabel: 'محاذاة النص',
      dir: 'rtl',
      variant: 'outline',
      children: h => [
        h.span([h.DataAttribute('icon', 'inline-start')], [icon('alignRight')]),
        h.span(
          [h.DataAttribute('icon', 'inline-start')],
          [icon('alignCenter')],
        ),
        h.span([h.DataAttribute('icon', 'inline-start')], [icon('alignLeft')]),
      ],
    },
    controller,
  )

export const ToggleGroupSizes = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html => {
  const h = html<Message>()

  return h.div(
    [h.Class('flex flex-wrap items-center gap-2')],
    [
      group<Message>(
        {
          ariaLabel: 'Small alignment',
          size: 'sm',
          variant: 'outline',
          children: alignmentChildren,
        },
        controller,
      ),
      group<Message>(
        {
          ariaLabel: 'Default alignment',
          size: 'default',
          variant: 'outline',
          children: alignmentChildren,
        },
        controller,
      ),
      group<Message>(
        {
          ariaLabel: 'Large alignment',
          size: 'lg',
          variant: 'outline',
          children: alignmentChildren,
        },
        controller,
      ),
    ],
  )
}

export const ToggleGroupSpacing = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  group<Message>(
    {
      ariaLabel: 'Spaced alignment',
      spacing: 4,
      variant: 'outline',
      children: alignmentChildren,
    },
    controller,
  )

export const ToggleGroupVertical = <Message = never>(
  controller?: ToggleGroupExampleController<Message>,
): Html =>
  group<Message>(
    {
      ariaLabel: 'Vertical text alignment',
      orientation: 'vertical',
      variant: 'outline',
      children: alignmentChildren,
    },
    controller,
  )

